using CourseCatalog.Models;

namespace CourseCatalog.Services;

public interface ICatalogService
{
    List<Department> GetDepartments();
    List<Course> GetCourses(string? searchTerm = null, int? departmentId = null);
    Course? GetCourseById(int id);
    List<Course> GetFeaturedCourses();
    bool SubmitEnrollment(EnrollmentRequest request);
}

using CourseCatalog.Models;

namespace CourseCatalog.Services;

public class CatalogService : ICatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments =
        [
            new() { Id = 1, Code = "CS",   Name = "Computer Science",  Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics",       Description = "Pure and applied mathematics courses." },
            new() { Id = 3, Code = "PHYS", Name = "Physics",           Description = "Explore the fundamental laws of the universe." },
            new() { Id = 4, Code = "ENG",  Name = "English",           Description = "Literature, writing, and communication studies." },
            new() { Id = 5, Code = "HIST", Name = "History",           Description = "Examine events, cultures, and societies across time." },
        ];

        _instructors =
        [
            new() { Id = 1, Name = "Dr. Ada Lovelace",    Title = "Professor",           Bio = "Expert in algorithms and programming theory with 20 years of teaching experience. Published extensively on computational thinking and software design patterns.", Email = "alovelace@university.edu" },
            new() { Id = 2, Name = "Dr. Alan Turing",     Title = "Associate Professor", Bio = "Specializes in theoretical computer science and artificial intelligence. Leads the university's Machine Learning Research Lab.", Email = "aturing@university.edu" },
            new() { Id = 3, Name = "Dr. Emmy Noether",    Title = "Professor",           Bio = "Renowned mathematician focusing on abstract algebra and theoretical physics. Recipient of the Distinguished Teaching Award.", Email = "enoether@university.edu" },
            new() { Id = 4, Name = "Dr. Richard Feynman", Title = "Professor",           Bio = "Award-winning physicist known for making complex concepts accessible. Author of several popular science books.", Email = "rfeynman@university.edu" },
            new() { Id = 5, Name = "Dr. Maya Angelou",    Title = "Professor",           Bio = "Acclaimed author and poet bringing decades of literary expertise to the classroom. Focuses on creative writing and American literature.", Email = "mangelou@university.edu" },
            new() { Id = 6, Name = "Dr. Howard Zinn",     Title = "Associate Professor", Bio = "Historian and social activist specializing in labor history and civil rights movements in America.", Email = "hzinn@university.edu" },
        ];

        _courses =
        [
            new() { Id = 1,  Code = "CS 101",   Title = "Introduction to Computer Science", Description = "Foundational course covering computational thinking, basic programming in Python, and an overview of computer science as a discipline. No prior experience required.", Credits = 3, Schedule = "MWF 9:00–9:50 AM",   Room = "Science Hall 201",   DepartmentId = 1, Department = _departments[0], Instructor = _instructors[0], IsFeatured = true },
            new() { Id = 2,  Code = "CS 201",   Title = "Data Structures & Algorithms",     Description = "In-depth study of arrays, linked lists, trees, graphs, sorting, and searching. Emphasis on algorithmic complexity and practical problem solving.", Credits = 4, Schedule = "TTh 10:30–11:50 AM", Room = "Science Hall 305",   DepartmentId = 1, Department = _departments[0], Instructor = _instructors[0], IsFeatured = false },
            new() { Id = 3,  Code = "CS 310",   Title = "Artificial Intelligence",          Description = "Survey of AI techniques including search, knowledge representation, machine learning, and natural language processing.", Credits = 3, Schedule = "MWF 1:00–1:50 PM",   Room = "Tech Center 110",    DepartmentId = 1, Department = _departments[0], Instructor = _instructors[1], IsFeatured = true },
            new() { Id = 4,  Code = "CS 350",   Title = "Software Engineering",             Description = "Principles of software development lifecycle, agile methodologies, version control, testing strategies, and team collaboration.", Credits = 3, Schedule = "TTh 2:00–3:20 PM",   Room = "Tech Center 215",    DepartmentId = 1, Department = _departments[0], Instructor = _instructors[1], IsFeatured = false },
            new() { Id = 5,  Code = "MATH 101", Title = "Calculus I",                       Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics, engineering, and economics.", Credits = 4, Schedule = "MWF 8:00–8:50 AM",   Room = "Math Building 101",  DepartmentId = 2, Department = _departments[1], Instructor = _instructors[2], IsFeatured = true },
            new() { Id = 6,  Code = "MATH 201", Title = "Linear Algebra",                   Description = "Vector spaces, matrices, determinants, eigenvalues, and linear transformations. Essential for advanced science and engineering courses.", Credits = 3, Schedule = "TTh 9:00–10:20 AM",  Room = "Math Building 203",  DepartmentId = 2, Department = _departments[1], Instructor = _instructors[2], IsFeatured = false },
            new() { Id = 7,  Code = "MATH 301", Title = "Abstract Algebra",                 Description = "Groups, rings, fields, and homomorphisms. A proof-intensive course for mathematics majors.", Credits = 3, Schedule = "MWF 11:00–11:50 AM", Room = "Math Building 305",  DepartmentId = 2, Department = _departments[1], Instructor = _instructors[2], IsFeatured = false },
            new() { Id = 8,  Code = "PHYS 101", Title = "General Physics I",                Description = "Mechanics, thermodynamics, and waves. Calculus-based approach with weekly laboratory sessions.", Credits = 4, Schedule = "MWF 10:00–10:50 AM", Room = "Physics Lab 100",    DepartmentId = 3, Department = _departments[2], Instructor = _instructors[3], IsFeatured = true },
