arguments.file_text:
@using CourseCatalog.Models

<div class="card course-card h-100">
    <div class="card-body d-flex flex-column">
        <span class="badge bg-secondary mb-2 align-self-start">@Course.Department.Code</span>
        <h5 class="card-title">@Course.Code — @Course.Title</h5>
        <p class="card-text text-muted flex-grow-1">@Truncate(Course.Description, 120)</p>
        <div class="d-flex justify-content-between align-items-center mt-2">
            <small class="text-body-secondary">@Course.Credits credits · @Course.Schedule</small>
            <a href="courses/@Course.Id" class="btn btn-sm btn-outline-primary">Details</a>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Course Course { get; set; } = default!;

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : string.Concat(text.AsSpan(0, maxLength), "…");
}

@using CourseCatalog.Models

<div class="card instructor-bio">
    <div class="card-body">
        <h5 class="card-title">@Instructor.Name</h5>
        <h6 class="card-subtitle mb-2 text-muted">@Instructor.Title</h6>
        <p class="card-text">@Instructor.Bio</p>
        <a href="mailto:@Instructor.Email" class="card-link">@Instructor.Email</a>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Instructor Instructor { get; set; } = default!;
}

@using CourseCatalog.Models

<div class="department-links">
    <h4>Departments</h4>
    <div class="list-group">
        @foreach (var dept in Departments)
        {
            <a href="courses?department=@dept.Id" class="list-group-item list-group-item-action">
                <strong>@dept.Code</strong> — @dept.Name
            </a>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public List<Department> Departments { get; set; } = [];
}

@using CourseCatalog.Models

<div class="row g-3 mb-4">
    <div class="col-md-8">
        <input type="text"
               class="form-control"
               placeholder="Search courses by title, code, or instructor…"
               @bind="SearchTerm"
               @bind:event="oninput"
               @bind:after="OnFilterChanged" />
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="SelectedDepartmentId" @bind:after="OnFilterChanged">
            <option value="0">All Departments</option>
            @foreach (var dept in Departments)
            {
                <option value="@dept.Id">@dept.Code — @dept.Name</option>
            }
        </select>
    </div>
</div>

@code {
    [Parameter] public string SearchTerm { get; set; } = string.Empty;
    [Parameter] public int SelectedDepartmentId { get; set; }
    [Parameter, EditorRequired] public List<Department> Departments { get; set; } = [];
    [Parameter] public EventCallback<string> SearchTermChanged { get; set; }
    [Parameter] public EventCallback<int> SelectedDepartmentIdChanged { get; set; }
    [Parameter] public EventCallback OnFiltersChanged { get; set; }

    private async Task OnFilterChanged()
    {
        await SearchTermChanged.InvokeAsync(SearchTerm);
        await SelectedDepartmentIdChanged.InvokeAsync(SelectedDepartmentId);
        await OnFiltersChanged.InvokeAsync();
    }
}

@using CourseCatalog.Models

@if (Courses.Count == 0)
{
    <div class="alert alert-info">No courses match your search criteria.</div>
}
else
{
    <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
        @foreach (var course in Courses)
        {
            <div class="col">
                <CourseCatalog.Components.Shared.CourseCard Course="course" />
            </div>
        }
    </div>
}

@code {
    [Parameter, EditorRequired]
    public List<Course> Courses { get; set; } = [];
}

