    {
        _featured = CatalogService.GetFeaturedCourses();
        _departments = CatalogService.GetDepartments();
    }
}

arguments.file_text:
@page "/courses"
@using CourseCatalog.Models
@using CourseCatalog.Services
@inject ICatalogService CatalogService
@inject NavigationManager Nav

<PageTitle>Courses — University Course Catalog</PageTitle>

<h2 class="mb-3">Course Catalog</h2>

<CourseCatalog.Components.Shared.CourseFilters
    @bind-SearchTerm="_searchTerm"
    @bind-SelectedDepartmentId="_selectedDeptId"
    Departments="_departments"
    OnFiltersChanged="ApplyFilters" />

<CourseCatalog.Components.Shared.CourseList Courses="_filteredCourses" />

@code {
    private string _searchTerm = string.Empty;
    private int _selectedDeptId;
    private List<Department> _departments = [];
    private List<Course> _filteredCourses = [];

    [SupplyParameterFromQuery(Name = "department")]
    public int? DepartmentFromQuery { get; set; }

    [SupplyParameterFromQuery(Name = "search")]
    public string? SearchFromQuery { get; set; }

    protected override void OnInitialized()
    {
        _departments = CatalogService.GetDepartments();

        if (DepartmentFromQuery.HasValue)
            _selectedDeptId = DepartmentFromQuery.Value;
        if (!string.IsNullOrEmpty(SearchFromQuery))
            _searchTerm = SearchFromQuery;

        LoadCourses();
    }

    private void ApplyFilters() => LoadCourses();

    private void LoadCourses()
    {
        int? deptFilter = _selectedDeptId > 0 ? _selectedDeptId : null;
        string? searchFilter = string.IsNullOrWhiteSpace(_searchTerm) ? null : _searchTerm;
        _filteredCourses = CatalogService.GetCourses(searchFilter, deptFilter);
    }
}

@page "/courses/{Id:int}"
@using CourseCatalog.Models
@using CourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>@(_course?.Title ?? "Course") — University Course Catalog</PageTitle>

@if (_course is null)
{
    <div class="alert alert-warning">Course not found.</div>
    <a href="courses" class="btn btn-outline-primary">Back to Catalog</a>
}
else
{
    <nav aria-label="breadcrumb" class="mb-3">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item active" aria-current="page">@_course.Code</li>
        </ol>
    </nav>

    <div class="row">
        <div class="col-lg-8">
            <h2>@_course.Code — @_course.Title</h2>
            <span class="badge bg-secondary mb-3">@_course.Department.Name</span>

            <p class="lead">@_course.Description</p>

            <table class="table table-bordered w-auto mt-3">
                <tbody>
                    <tr><th>Credits</th><td>@_course.Credits</td></tr>
                    <tr><th>Schedule</th><td>@_course.Schedule</td></tr>
                    <tr><th>Room</th><td>@_course.Room</td></tr>
                    <tr><th>Department</th><td>@_course.Department.Name (@_course.Department.Code)</td></tr>
