    <p class="lead text-muted">Explore our departments, browse courses, and enroll today.</p>
    <a href="courses" class="btn btn-primary btn-lg me-2">Browse Courses</a>
    <a href="enroll" class="btn btn-outline-secondary btn-lg">Enroll Now</a>
</div>

<div class="row">
    <div class="col-lg-8 mb-4">
        <CourseCatalog.Components.Shared.FeaturedCourses Courses="_featured" />
    </div>
    <div class="col-lg-4">
        <CourseCatalog.Components.Shared.DepartmentLinks Departments="_departments" />
    </div>
</div>

@code {
    private List<Course> _featured = [];
    private List<Department> _departments = [];

    protected override void OnInitialized()
    {
        _featured = CatalogService.GetFeaturedCourses();
        _departments = CatalogService.GetDepartments();
    }
}

toolArgs.file_text:
@page "/courses/{Id:int}"
@using CourseCatalog.Models
@using CourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>@(_course?.Title ?? "Course") — University Course Catalog</PageTitle>

@if (_course is null)
{
    <div class="alert alert-warning">Course not found.</div>
    <a href="courses" class="btn btn-outline-primary">Back to Catalog</a>
}
else
{
    <nav aria-label="breadcrumb" class="mb-3">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item active" aria-current="page">@_course.Code</li>
        </ol>
    </nav>

    <div class="row">
        <div class="col-lg-8">
            <h2>@_course.Code — @_course.Title</h2>
            <span class="badge bg-secondary mb-3">@_course.Department.Name</span>

            <p class="lead">@_course.Description</p>

            <table class="table table-bordered w-auto mt-3">
                <tbody>
                    <tr><th>Credits</th><td>@_course.Credits</td></tr>
                    <tr><th>Schedule</th><td>@_course.Schedule</td></tr>
                    <tr><th>Room</th><td>@_course.Room</td></tr>
                    <tr><th>Department</th><td>@_course.Department.Name (@_course.Department.Code)</td></tr>
                </tbody>
            </table>

            <a href="enroll?course=@_course.Id" class="btn btn-primary mt-2">Enroll in This Course</a>
        </div>
        <div class="col-lg-4">
            <h4 class="mb-3">Instructor</h4>
            <CourseCatalog.Components.Shared.InstructorBio Instructor="_course.Instructor" />
        </div>
    </div>
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Course? _course;

    protected override void OnInitialized()
    {
        _course = CatalogService.GetCourseById(Id);
    }
}

@page "/enroll"
@using CourseCatalog.Models
@using CourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>Enroll — University Course Catalog</PageTitle>

<h2 class="mb-3">Enrollment Request</h2>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Thank you, <strong>@_model.StudentName</strong>. Your enrollment request for
        <strong>@_courses.First(c => c.Id == _model.CourseId).Title</strong> has been received.</p>
        <hr />
        <p class="mb-0">You'll receive a confirmation at your university email within 2 business days.</p>
    </div>
    <button class="btn btn-outline-primary" @onclick="Reset">Submit Another Request</button>
}
else
{
    <div class="row">
        <div class="col-lg-6">
            <EditForm Model="_model" OnValidSubmit="HandleSubmit" FormName="enrollment">
                <DataAnnotationsValidator />
                <ValidationSummary class="text-danger" />

                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <InputText id="studentName" class="form-control" @bind-Value="_model.StudentName" />
                    <ValidationMessage For="() => _model.StudentName" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <InputText id="studentId" class="form-control" placeholder="e.g. STU12345" @bind-Value="_model.StudentId" />
                    <ValidationMessage For="() => _model.StudentId" class="text-danger" />
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <InputSelect id="courseId" class="form-select" @bind-Value="_model.CourseId">
                        <option value="0">— Select a course —</option>
                        @foreach (var course in _courses)
                        {
                            <option value="@course.Id">@course.Code — @course.Title (@course.Credits cr)</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => _model.CourseId" class="text-danger" />
                </div>

                <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
            </EditForm>
        </div>
    </div>
}

@code {
    private EnrollmentRequest _model = new();
    private List<Course> _courses = [];
    private bool _submitted;

    [SupplyParameterFromQuery(Name = "course")]
    public int? PreselectedCourseId { get; set; }

    protected override void OnInitialized()
    {
        _courses = CatalogService.GetCourses();
        if (PreselectedCourseId.HasValue)
            _model.CourseId = PreselectedCourseId.Value;
    }

    private void HandleSubmit()
    {
        _submitted = CatalogService.SubmitEnrollment(_model);
    }

    private void Reset()
    {
        _model = new();
        _submitted = false;
    }
}

